using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed discriminator from "Discriminator" to "$type".
            // Revert to legacy name for compatibility with existing 500K documents.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "EntityType|Key" to just "Key".
            // Revert to legacy format for compatibility with existing documents.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

// Generates ids in the legacy EF Core 8 format: "Product|{key}"
using Microsoft.EntityFrameworkCore.ValueGeneration;
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"Product|{entry.Property("Id").CurrentValue}";
}

